message.content:
{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires both a mathematical model to represent the uncertainty of polyomino placements and an optimization strategy to minimize probing costs. I am splitting this into a modeling task and a search/optimization task.",
  "helpers": [
    {
      "label": "modeling_helper",
      "instructions": "Develop a probabilistic or geometric model that represents the set of all possible valid placements of the given polyomino shapes within the grid. The model should account for the constraints of the shapes and provide a way to calculate the probability or likelihood of any specific cell being part of an oil field based on the known shapes."
    },
    {
      "label": "search_strategy_helper",
      "instructions": "Design an adaptive search algorithm that selects the optimal sequence of drilling and aggregate queries to minimize total cost. The strategy should use the model from the first helper to prioritize probes that maximize information gain (reducing uncertainty about cell occupancy) while balancing the cost of drilling versus the cost of noisy aggregate queries."
    }
  ],
  "synthesis_brief": "Combine the probabilistic model of polyomino placements with the adaptive search strategy to produce a sequence of probes and a final set of guessed oil-containing cells that minimizes the total cost."
}

